var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이 아이들이 바로 <color=#ffd34c>지식의 호수</color>예요.","JPN":"この子たちこそが<color=#ffd34c>知識の湖</color>なんです。","ENG":"They are the <color=#ffd34c>Lake of Knowledge</color>.","TWN":"這些孩子就是<color=#ffd34c>知識之湖</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"세상의 모든 지식을 담을 수 있는 서고죠.","JPN":"この世のすべての知識を宿せる書庫なんですよ。","ENG":"An archive that's able to store all the knowledge in this world.","TWN":"是能夠收納世界上所有知識的書庫。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 촉수들이...... 지식의 호수라고요?","JPN":"その触手が……知識の湖？","ENG":"Those tentacles... They're the Lake of Knowledge?","TWN":"妳說這些觸手……是知識之湖？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 학회는 여태 코앞에 있는 호수를 내버려 두고 헛된 짓만 했단 말인가요?","JPN":"つまり、学会はこんな目の前に湖があるのに、湖を探していたということですか？","ENG":"Then what has the Society been doing all along? The Lake has been right under their noses!","TWN":"也就是學會放著眼前的知識之湖不管，都在做些沒用的事情？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"호수는 완전하지 않아요.","JPN":"湖は完全ではありません。","ENG":"The Lake is incomplete.","TWN":"湖並不完整。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"오래 전...... 아주 오래 전에 수많은 조각으로 나눠져서 뿔뿔이 흩어졌거든요.","JPN":"遥か昔……気が遠くなるほど昔に、多くのカケラに分けられて散り散りになってしまいましたから。","ENG":"Long ago, it was split into numerous pieces and scattered across the world.","TWN":"很久以前……很久很久以前，它被分成很多碎片，散落在各地。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"책에 비유하면 낱장이나 글자가 사라져 버린 셈이죠.","JPN":"本で言えば、ページや文字が消えてしまっている状態ですね。","ENG":"Now it's like a book with pages ripped out and words and letters missing.","TWN":"用書來比喻的話，就是其中的書頁或文字消失了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래서 이 아이들은 무척 예민해요.","JPN":"そのせいで、この子たちもかなり気が立っているんですよ。","ENG":"That's why they are very sensitive.","TWN":"所以這些孩子們非常敏感。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"항상 누군가가 곁에서 돌봐 줘야 말썽을 피우지 않죠.","JPN":"常に誰かが傍で世話をしないと暴れ出すんです。","ENG":"You always need to take care of them so that they won't cause any trouble.","TWN":"必須時時有人在身旁照顧，它們才不會惹出麻煩。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이건 학회장의 역할 중에서도 가장 중요한 직무랍니다.","JPN":"これは学会長の役割の中でも、最も重要な職務です。","ENG":"It's the most important duty of the President of the Society.","TWN":"這也是學會長的職務中最重要的工作。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼...... 계승식이라는 건......","JPN":"じゃあ……継承式というのは……","ENG":"You mean... the succession ceremony is...","TWN":"那……所謂繼承儀式……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설마 그 괴물들을 다음 학회장 몸으로 옮기기 위한 의식인가요?","JPN":"まさか、その怪物を次の学会長の体に移すための儀式なのですか？","ENG":"the event where you transfer those monsters from the former President to the next one?","TWN":"該不會就是為了把這些怪物轉移到下任學會長的身體裡吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맞아요. 이해가 무척 빠르시네요.","JPN":"ええ。理解が早くて助かります。","ENG":"Precisely. You're very quick to understand.","TWN":"沒錯。您理解得很快呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"역시 레지나 님은 훌륭한 차기 학회장감이세요.","JPN":"やっぱり、レジーナ様は立派な次期学会長になれそうですね。","ENG":"We knew you were a perfect material for the next President of the Society.","TWN":"蕾佳娜大人果然是優秀的下任學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"음, 음. 육아 하면 레지나지. 적성이랑 잘 맞겠네.","JPN":"うんうん。育児と言えばレジーナだよね。向いてると思うよ。","ENG":"Uh-huh. Regina's the one if you're looking for someone to take care of babies. She's a good fit for the job.","TWN":"嗯，嗯。說到養小孩就想到蕾佳娜， 相性果然很合呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신은 누구 맘대로 남의 적성을 결정해요?! 제 진로는 고고학으로 정해져 있습니다!","JPN":"勝手に人の向き不向きを決めないでもらえますか！？　私の進路は考古学と決めているのです！","ENG":"What are you to decide what I'm good at? My career path will be in archaeology!","TWN":"妳憑什麼隨便決定別人的相性啊？我已經決定要走考古學的道路了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어쨌든......","JPN":"とにかく……","ENG":"Anyway...","TWN":"總之……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};